import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { authService } from '../services/api';
import '../styles/auth.css';

const Register = () => {
    const navigate = useNavigate();
    const [role, setRole] = useState('patient');
    const [formData, setFormData] = useState({
        username: '',
        email: '',
        password: '',
        first_name: '',
        last_name: '',
        phone: '',
    });
    const [doctorData, setDoctorData] = useState({
        specialization: 'general',
        license_number: '',
        qualification: '',
        years_of_experience: 0,
        consultation_fee: 500,
    });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleDoctorDataChange = (e) => {
        const { name, value } = e.target;
        setDoctorData({ ...doctorData, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');
        
        try {
            const registrationData = {
                ...formData,
                role,
                ...(role === 'doctor' && doctorData),
            };
            
            const response = await authService.register(registrationData);
            localStorage.setItem('access_token', response.data.access);
            localStorage.setItem('refresh_token', response.data.refresh);
            localStorage.setItem('user', JSON.stringify(response.data.user));
            
            navigate(role === 'admin' ? '/admin/dashboard' : role === 'doctor' ? '/doctor/dashboard' : '/patient/dashboard');
        } catch (err) {
            console.error('Registration error:', err);
            const errorMsg = err.response?.data?.detail || 
                           err.response?.data?.message ||
                           JSON.stringify(err.response?.data) || 
                           'Registration failed. Please try again.';
            setError(errorMsg);
        } finally {
            setLoading(false);
        }
    };

    const roleButtons = [
        React.createElement('button', {
            type: 'button',
            className: `role-btn ${role === 'admin' ? 'active' : ''}`,
            onClick: () => setRole('admin')
        }, '🔐 Admin'),
        React.createElement('button', {
            type: 'button',
            className: `role-btn ${role === 'patient' ? 'active' : ''}`,
            onClick: () => setRole('patient')
        }, '👤 Patient'),
        React.createElement('button', {
            type: 'button',
            className: `role-btn ${role === 'doctor' ? 'active' : ''}`,
            onClick: () => setRole('doctor')
        }, '👨‍⚕️ Doctor')
    ];

    const doctorFields = role === 'doctor' ? [
        React.createElement('hr', null),
        React.createElement('h3', null, 'Professional Information'),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'specialization' }, 'Specialization'),
            React.createElement(
                'select',
                {
                    id: 'specialization',
                    name: 'specialization',
                    value: doctorData.specialization,
                    onChange: handleDoctorDataChange
                },
                React.createElement('option', { value: 'general' }, 'General Medicine'),
                React.createElement('option', { value: 'cardiology' }, 'Cardiology'),
                React.createElement('option', { value: 'dermatology' }, 'Dermatology'),
                React.createElement('option', { value: 'neurology' }, 'Neurology'),
                React.createElement('option', { value: 'orthopedics' }, 'Orthopedics'),
                React.createElement('option', { value: 'pediatrics' }, 'Pediatrics'),
                React.createElement('option', { value: 'psychiatry' }, 'Psychiatry'),
                React.createElement('option', { value: 'surgery' }, 'Surgery'),
                React.createElement('option', { value: 'gynecology' }, 'Gynecology')
            )
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'license_number' }, 'License Number'),
            React.createElement('input', {
                type: 'text',
                id: 'license_number',
                name: 'license_number',
                value: doctorData.license_number,
                onChange: handleDoctorDataChange,
                required: true,
                placeholder: 'Medical License Number'
            })
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'qualification' }, 'Qualification'),
            React.createElement('input', {
                type: 'text',
                id: 'qualification',
                name: 'qualification',
                value: doctorData.qualification,
                onChange: handleDoctorDataChange,
                required: true,
                placeholder: 'e.g., MBBS, MD'
            })
        ),
        React.createElement(
            'div',
            { className: 'form-row' },
            React.createElement(
                'div',
                { className: 'form-group' },
                React.createElement('label', { htmlFor: 'years_of_experience' }, 'Years of Experience'),
                React.createElement('input', {
                    type: 'number',
                    id: 'years_of_experience',
                    name: 'years_of_experience',
                    value: doctorData.years_of_experience,
                    onChange: handleDoctorDataChange,
                    min: '0'
                })
            ),
            React.createElement(
                'div',
                { className: 'form-group' },
                React.createElement('label', { htmlFor: 'consultation_fee' }, 'Consultation Fee ($)'),
                React.createElement('input', {
                    type: 'number',
                    id: 'consultation_fee',
                    name: 'consultation_fee',
                    value: doctorData.consultation_fee,
                    onChange: handleDoctorDataChange,
                    min: '0',
                    step: '0.01'
                })
            )
        )
    ] : [];

    const formElements = [
        React.createElement(
            'div',
            { className: 'form-row' },
            React.createElement(
                'div',
                { className: 'form-group' },
                React.createElement('label', { htmlFor: 'first_name' }, 'First Name'),
                React.createElement('input', {
                    type: 'text',
                    id: 'first_name',
                    name: 'first_name',
                    value: formData.first_name,
                    onChange: handleChange,
                    required: true,
                    placeholder: 'First name'
                })
            ),
            React.createElement(
                'div',
                { className: 'form-group' },
                React.createElement('label', { htmlFor: 'last_name' }, 'Last Name'),
                React.createElement('input', {
                    type: 'text',
                    id: 'last_name',
                    name: 'last_name',
                    value: formData.last_name,
                    onChange: handleChange,
                    required: true,
                    placeholder: 'Last name'
                })
            )
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'username' }, 'Username'),
            React.createElement('input', {
                type: 'text',
                id: 'username',
                name: 'username',
                value: formData.username,
                onChange: handleChange,
                required: true,
                placeholder: 'Choose a username'
            })
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'email' }, 'Email'),
            React.createElement('input', {
                type: 'email',
                id: 'email',
                name: 'email',
                value: formData.email,
                onChange: handleChange,
                required: true,
                placeholder: 'your@email.com'
            })
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'phone' }, 'Phone'),
            React.createElement('input', {
                type: 'tel',
                id: 'phone',
                name: 'phone',
                value: formData.phone,
                onChange: handleChange,
                placeholder: 'Phone number'
            })
        ),
        React.createElement(
            'div',
            { className: 'form-group' },
            React.createElement('label', { htmlFor: 'password' }, 'Password'),
            React.createElement('input', {
                type: 'password',
                id: 'password',
                name: 'password',
                value: formData.password,
                onChange: handleChange,
                required: true,
                placeholder: 'Enter a strong password'
            })
        ),
        ...doctorFields,
        React.createElement('button', {
            type: 'submit',
            disabled: loading,
            className: 'btn btn-primary'
        }, loading ? 'Registering...' : 'Register')
    ];

    return React.createElement(
        'div',
        { className: 'auth-container' },
        React.createElement(
            'div',
            { className: 'auth-card register-card' },
            React.createElement(
                'div',
                { className: 'auth-header' },
                React.createElement('h1', null, '🏥 Hospital Management System'),
                React.createElement('p', null, 'Create your account')
            ),
            error && React.createElement('div', { className: 'alert alert-error' }, error),
            React.createElement(
                'div',
                { className: 'role-selector' },
                React.createElement('label', null, 'I am a:'),
                React.createElement('div', { className: 'role-buttons' }, ...roleButtons)
            ),
            React.createElement(
                'form',
                { onSubmit: handleSubmit, className: 'auth-form' },
                ...formElements
            ),
            React.createElement(
                'div',
                { className: 'auth-footer' },
                React.createElement(
                    'p',
                    null,
                    'Already have an account? ',
                    React.createElement(Link, { to: '/login' }, 'Login here')
                )
            )
        )
    );
};

export default Register;
